def normalize_collaboration(collaboration):
    if not collaboration:
    return []
    collaboration = collaboration.strip()
    if collaboration.startswith('(') and collaboration.endswith(')'):
    collaboration = collaboration[1:-1]
    collaborations = _RE_AND.split(collaboration)
    collaborations = (_RE_COLLABORATION_LEADING.sub('', collab) for collab in collaborations)
    collaborations = (_RE_COLLABORATION_TRAILING.sub('', collab) for collab in collaborations)
    return [collab.strip() for collab in collaborations]

def write_smet(filename, data, metadata, nodata_value=-999, mode='h', check_nan=True):
    dict_d = {'tmean': 'TA', 'tmin': 'TMAX', 'tmax': 'TMIN', 'precip': 'PSUM', 'glob': 'ISWR', 'hum': 'RH', 'wind': 'VW'}
    dict_h = {'temp': 'TA', 'precip': 'PSUM', 'glob': 'ISWR', 'hum': 'RH', 'wind': 'VW'}
    if mode == 'd':
    data = data.rename(columns=dict_d)
    if mode == 'h':
    data = data.rename(columns=dict_h)
    if check_nan:
    datas_in = data.sum().dropna().to_frame().T
    drop = [data_nan for data_nan in data.columns if data_nan not in datas_in]
    data = data.drop(drop, axis=1)
    with open(filename, 'w') as f:
    if mode == 'd':
        t = '%Y-%m-%dT00:00'
    if mode == 'h':
        t = '%Y-%m-%dT%H:%M'
    data['timestamp'] = [d.strftime(t) for d in data.index]
    cols = data.columns.tolist()
    cols = cols[-1:] + cols[:-1]
    data = data[cols]
    metadata['fields'] = ' '.join(data.columns)
    metadata['units_multiplier'] = len(metadata['fields'].split()) * '1 '
    f.write('SMET 1.1 ASCII\n')
    f.write('[HEADER]\n')
    for k, v in metadata.items():
        f.write('{} = {}\n'.format(k, v))
    f.write('[DATA]\n')
    data_str = data.fillna(nodata_value).to_string(header=False, index=False, float_format=lambda x: '{:.2f}'.format(x))
    f.write(data_str)

