def _roll_negative_time_fields(year, month, day, hour, minute, second):
    if second < 0:
    minute += int(second / 60.0)
    minute -= 1
    second %= 60
    if minute < 0:
    hour += int(minute / 60.0)
    hour -= 1
    minute %= 60
    if hour < 0:
    day += int(hour / 24.0)
    day -= 1
    hour %= 24
    if day < 0:
    month += int(day / 30.0)
    month -= 1
    day %= 30
    if month < 0:
    year += int(month / 12.0)
    year -= 1
    month %= 12
    return (year, month, day, hour, minute, second)

