def make_registry(directory, output, recursive=True):
    directory = Path(directory)
    if recursive:
    pattern = '**/*'
else:
    pattern = '*'
    files = sorted([str(path.relative_to(directory)) for path in directory.glob(pattern) if path.is_file()])
